<template>
    <div class="my max-height-width">
        <div class='my-head'>
            <p>
                <router-link to='/study/first/first01'>首页</router-link>
            </p>
            <p
                v-for='(item, index) in myData'
                :key='index'
                @click='goto(item)'>
                {{item.value}}
            </p>
        </div>
        <div class='my-container max-height-width'>
            <div class='left-nav'>
                <ul>
                    <li
                        v-for='(item, index) in navList'
                        @click.self.prevent='changePage(item, index)'
                        :class='{active: flag === index}'
                        :key='index'>
                        {{item.value}}
                        <ul v-if='item.show'>
                            <li
                                v-for='(child, num) in item.children'
                                @click='goPath(child)'
                                :key='num'>
                                {{child.value}}
                            </li>
                        </ul>
                    </li>
                </ul>
            </div>
            <div class='content'>
                <router-view/>
            </div>
        </div>
    </div>
</template>
<script>
    export default {
        data() {
            return {
                flag: 0,  
                myData: [
                    {
                        value: 'home',
                        children: [
                            {
                                value: 'home01',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/home/home01/list01' },
                                    { value: 'list', path: '/my/home/home01/list02' },
                                    { value: 'list', path: '/my/home/home01/list03' },
                                    { value: 'list', path: '/my/home/home01/list04' },
                                ]
                            },
                            {
                                value: 'home02',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/home/home02/list01' },
                                    { value: 'list', path: '/my/home/home02/list02' },
                                    { value: 'list', path: '/my/home/home02/list03' },
                                    { value: 'list', path: '/my/home/home02/list04' },
                                ]
                            },
                            {
                                value: 'home03',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/home/home03/list01' },
                                    { value: 'list', path: '/my/home/home03/list02' },
                                    { value: 'list', path: '/my/home/home03/list03' },
                                    { value: 'list', path: '/my/home/home03/list04' },
                                ]
                            },
                            {
                                value: 'home04',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/home/home04/list01' },
                                    { value: 'list', path: '/my/home/home04/list02' },
                                    { value: 'list', path: '/my/home/home04/list03' },
                                    { value: 'list', path: '/my/home/home04/list04' },
                                ]
                            },
                        ]
                    },
                    {
                        value: 'image',
                        children: [
                            {
                                value: 'image',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/image/image01/list01' },
                                    { value: 'list', path: '/my/image/image01/list02' },
                                    { value: 'list', path: '/my/image/image01/list03' },
                                    { value: 'list', path: '/my/image/image01/list04' }
                                ]
                            }
                        ]
                    },
                    {
                        value: 'vedio',
                        children: [
                            {
                                value: 'vedio',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/vedio/vedio01/list01' },
                                    { value: 'list', path: '/my/vedio/vedio01/list02' },
                                    { value: 'list', path: '/my/vedio/vedio01/list03' },
                                    { value: 'list', path: '/my/vedio/vedio01/list04' }
                                ]
                            }
                        ]
                    },
                    {
                        value: 'audio',
                        children: [
                            {
                                value: 'audio',
                                show: false,
                                children: [
                                    { value: 'list', path: '/my/audio/audio01/list01' },
                                    { value: 'list', path: '/my/audio/audio01/list02' },
                                    { value: 'list', path: '/my/audio/audio01/list03' },
                                    { value: 'list', path: '/my/audio/audio01/list04' }
                                ]
                            }
                        ]
                    },
                    // {value: 'swiper', path: '/swiper'}
                ],
                navList: []
            };
        },
        created() {
            this.navList = this.myData[0].children
        },
        methods: {
            goPath(data) {
                this.$router.push(data.path);
            },
            goto(data) {
                this.flag = 0;
                this.navList = data.children;
                this.$router.push(data.children[0].children[0].path);
            },
            changePage(data, index) {
                this.flag = index;
                data.show = !data.show;
            }
        }
    };
</script>

